var e=[{id:`L2_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`으아아아!!!`,JPN:`うわあああ！`,ENG:`Aaaah!`,TWN:`呃啊啊啊！！！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_SURPRISE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`떨어지자마자 갑자기 침식체라니!`,JPN:`落とされたところにいきなり侵食体なんて！`,ENG:`I wasn't expecting a C.O. at the end of the tunnel!`,TWN:`一掉下來就撞上侵蝕體！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`이 회사는 왜 가는 곳마다 위험한 게 돌아다니는 거야?!`,JPN:`この会社はなんで行く先々にこんな危ないモノが徘徊してるの！？`,ENG:`Why is this company filled with danger?`,TWN:`這家公司怎麼到處都有危險的東西啊？！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L8_1`,type:`dialog`,speaker:null,text:{KOREA:`거기 조심해!`,JPN:`そこ、気を付けて！`,ENG:`Watch out!`,TWN:`小心！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L9_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`......뭐?`,JPN:`……え？`,ENG:`...Huh?`,TWN:`……什麼？`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L11_1`,type:`dialog`,speaker:null,text:{KOREA:`루미네이트......!`,JPN:`ルミネイト……！`,ENG:`Luminate...`,TWN:`魯米奈特……！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L12_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_BG`,text:{KOREA:`......킥!`,JPN:`……キック！`,ENG:`Kick!`,TWN:` ……吱！`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`RUMI_NPC_FOOLSDAY_BG`,face:`UNIT_SERIOUS`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`......흐음, 킥이랑 동시에 화려한 폭죽 같은 걸 터트리면 더 좋았으려나?`,JPN:`……う～ん、キックと同時に派手な爆竹でも使えばよかったのかな？`,ENG:`Hmm... Maybe I should have added some fancy fireworks effects.`,TWN:`……嗯，踢擊的同時放些華麗的鞭炮應該會更好吧？`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L20_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`아! 거기 괜찮아?`,JPN:`ねえ、大丈夫？`,ENG:`Oh! Are you okay?`,TWN:`啊！那個，你沒事吧？`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L21_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,text:{KOREA:`하아, 괜찮아. 덕분에 살았어.`,JPN:`はあ、平気。おかげで助かったよ。`,ENG:`I'm okay. You saved my butt.`,TWN:`哈啊，沒事，多虧你保住一命了。`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_NULL`,face:`UNIT_DESPAIR`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`새로운 궁극기를 테스트하려고 풀어놨던 녀석인데 여기까지 도망칠 줄은 몰랐네.`,JPN:`新しい究極スキルをテストしようと思って放した子なんだけど、ここまで逃げるとは思わなかったの。`,ENG:`I let the C.O. loose to test out my new Ultimate skill. I didn't know it'd come all the way over here.`,TWN:`爲了測試新的必殺技而解開的傢伙，沒想到會逃到這裡。`},stage:{bg:`DORMITORY_2`,slots:{L:null,C:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_LAUGH`},R:null}}},{id:`L25_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`그럼 결국 내가 쫓기는 원인을 제공한 것도 당신이란 소리잖아!`,JPN:`それはつまり、私が追われた原因はあんたってことでしょ！`,ENG:`You mean you're the reason I got chased like that?!`,TWN:`那麼害我被追殺的罪魁禍首原來也是你啊！`},stage:{bg:`DORMITORY_2`,slots:{L:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_HATE`},C:null,R:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`미안~ 혹시 어디 물린 곳 있어? 없어진 부분이 있으면 다시 그려줄 수도 있는데.`,JPN:`ごめーん、どっか嚙まれたりしてない？　消えたパーツがあるなら描き直してあげるよ。`,ENG:`Sorry, did it bite you? I can always draw you a new limb if you're missing any.`,TWN:`對不起～有被咬到的地方嗎？如果有咬到消失的部分，我可以重新畫給你。`},stage:{bg:`DORMITORY_2`,slots:{L:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_HATE`},C:null,R:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_LAUGH`}}}},{id:`L27_1`,type:`dialog`,speaker:`RUMI_NPC_FOOLSDAY_NULL`,text:{KOREA:`내 분야는 이펙트 쪽이지만 새로 그려 넣는 것 정도는 해줄 수 있거든!`,JPN:`アタシはエフェクト担当ではあるけど、描き足すくらいはできるからね！`,ENG:`I specialize in special effects, but I can draw you a new limb or two!`,TWN:`雖然我負責的領域主要還是特效方面，但至少可以重新畫進去！`},stage:{bg:`DORMITORY_2`,slots:{L:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_HATE`},C:null,R:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_PRIDE`}}}},{id:`L28_1`,type:`dialog`,speaker:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,text:{KOREA:`괜찮은 것 같아. ......아직은 말이지.`,JPN:`それは大丈夫そう……今のところはね。`,ENG:`I think I'm fine... for now.`,TWN:`感覺還好。 ………至少現在。`},stage:{bg:`DORMITORY_2`,slots:{L:{char_id:`YOO_MI_NA_NPC_FOOLSDAY_LITTLE`,face:`UNIT_DESPAIR`},C:null,R:{char_id:`RUMI_NPC_FOOLSDAY_NULL`,face:`UNIT_PRIDE`}}}}];export{e as default};